	.inputValidator((data: unknown) =>
		getOrganizerRegistrationsInputSchema.parse(data),
	)
	.handler(async ({ data }) => {
		const db = getDb()

		// Build where clause - exclude removed registrations
		const whereConditions = [
			eq(competitionRegistrationsTable.eventId, data.competitionId),
			ne(competitionRegistrationsTable.status, REGISTRATION_STATUS.REMOVED),
		]

		// Get registrations with user and division info using query builder
		const registrations = await db.query.competitionRegistrationsTable.findMany(
			{
				where: and(...whereConditions),
				orderBy: (table, { desc }) => [desc(table.registeredAt)],
				with: {
					user: {
						columns: {
							id: true,
							firstName: true,
							lastName: true,
							email: true,
							avatar: true,
							gender: true,
							dateOfBirth: true,
							affiliateName: true,
						},
					},
					division: {
						columns: {
							id: true,
							label: true,
							teamSize: true,
						},
					},
					athleteTeam: {
						with: {
							memberships: {
								columns: {
									id: true,
									userId: true,
									joinedAt: true,
								},
								where: eq(teamMembershipTable.isActive, true),
								with: {
									user: {
										columns: {
											id: true,
											firstName: true,
											lastName: true,
											email: true,
											avatar: true,
