/**
 * Get detailed registration information including payment and competition details
 */
export const getRegistrationDetailsFn = createServerFn({ method: "GET" })
	.inputValidator((data: unknown) =>
		z.object({ registrationId: z.string() }).parse(data),
	)
	.handler(async ({ data }): Promise<RegistrationDetails | null> => {
		const session = await requireVerifiedEmail()
		if (!session) throw new Error("Unauthorized")

		const db = getDb()
		const { competitionDivisionsTable } = await import("@/db/schema")

		// Get registration with all related data
		const registration = await db.query.competitionRegistrationsTable.findFirst(
			{
				where: eq(competitionRegistrationsTable.id, data.registrationId),
				with: {
					competition: {
						columns: {
							id: true,
							name: true,
							slug: true,
							startDate: true,
							endDate: true,
							profileImageUrl: true,
						},
					},
					division: {
						columns: {
							id: true,
							label: true,
							teamSize: true,
						},
					},
				},
			},
		)

		if (!registration) {
			return null
		}

		// Verify user is authorized to view this registration
		const isRegisteredUser = registration.userId === session.user.id
		let isTeamMember = false
		if (registration.athleteTeamId) {
			const membership = await db.query.teamMembershipTable.findFirst({
				where: and(
					eq(teamMembershipTable.teamId, registration.athleteTeamId),
					eq(teamMembershipTable.userId, session.user.id),
				),
			})
			isTeamMember = !!membership
		}
		if (!isRegisteredUser && !isTeamMember) {
			// Return null instead of throwing to allow route to show 404
			return null
		}

		// Parse related data (handle array vs single object)
		const competition = registration.competition
			? Array.isArray(registration.competition)
				? registration.competition[0]
				: registration.competition
			: null

		const division = registration.division
			? Array.isArray(registration.division)
				? registration.division[0]
				: registration.division
			: null

		// Get division description and fee from competition_divisions table
		let divisionDescription: string | null = null
		let divisionFeeCents: number | null = null

		if (competition?.id && division?.id) {
			const divisionConfig = await db.query.competitionDivisionsTable.findFirst(
				{
					where: and(
						eq(competitionDivisionsTable.competitionId, competition.id),
						eq(competitionDivisionsTable.divisionId, division.id),
					),
				},
			)
			if (divisionConfig) {
				divisionDescription = divisionConfig.description
				divisionFeeCents = divisionConfig.feeCents
			}
		}

		// Get purchase details if exists
		let purchase: RegistrationDetails["purchase"] = null

		if (registration.commercePurchaseId) {
			const purchaseRecord = await db.query.commercePurchaseTable.findFirst({
				where: eq(commercePurchaseTable.id, registration.commercePurchaseId),
			})
			if (purchaseRecord) {
				purchase = {
					id: purchaseRecord.id,
					totalCents: purchaseRecord.totalCents,
					status: purchaseRecord.status,
					completedAt: purchaseRecord.completedAt,
					stripePaymentIntentId: purchaseRecord.stripePaymentIntentId,
				}
			}
		}

		return {
			registrationId: registration.id,
			registeredAt: registration.registeredAt,
			teamName: registration.teamName,
			paymentStatus: registration.paymentStatus,
			paidAt: registration.paidAt,
			competition: competition
				? {
						id: competition.id,
						name: competition.name,
						slug: competition.slug,
						startDate: competition.startDate,
						endDate: competition.endDate,
						profileImageUrl: competition.profileImageUrl,
					}
				: null,
			division: division
				? {
						id: division.id,
						label: division.label,
						teamSize: division.teamSize,
						description: divisionDescription,
						feeCents: divisionFeeCents,
					}
				: null,
			purchase,
		}
	})

/**
 * Cancel any pending purchases for a user/competition
 * Used when user explicitly cancels from Stripe checkout
 * This releases the reservation immediately instead of waiting for timeout
 */
export const cancelPendingPurchaseFn = createServerFn({ method: "POST" })
	.inputValidator((data: unknown) =>
		z
			.object({
				userId: z.string().min(1, "User ID is required"),
				competitionId: z.string().min(1, "Competition ID is required"),
			})
			.parse(data),
	)
	.handler(async ({ data }) => {
		// Authenticate user
		const session = await requireVerifiedEmail()
		if (!session) throw new Error("Unauthorized")

		// Update request context
		updateRequestContext({ userId: session.user.id })
		addRequestContextAttribute("competitionId", data.competitionId)

		// Ensure user can only cancel their own pending purchases
		if (data.userId !== session.user.id) {
			logWarning({
				message: "[Registration] Cancel purchase denied - wrong user",
				attributes: {
					requestedUserId: data.userId,
					competitionId: data.competitionId,
				},
			})
			throw new Error("You can only cancel your own pending purchases")
		}

		const db = getDb()

		// Cancel any PENDING purchases for this user/competition
		await db
			.update(commercePurchaseTable)
			.set({ status: COMMERCE_PURCHASE_STATUS.CANCELLED })
			.where(
				and(
					eq(commercePurchaseTable.userId, data.userId),
					eq(commercePurchaseTable.competitionId, data.competitionId),
					eq(commercePurchaseTable.status, COMMERCE_PURCHASE_STATUS.PENDING),
				),
			)

		logInfo({
			message: "[Registration] Pending purchase cancelled",
			attributes: {
				competitionId: data.competitionId,
			},
		})

		return { success: true }
	})

// ============================================================================
// Remove Registration (Organizer Soft Delete)
// ============================================================================

const removeRegistrationInputSchema = z.object({
	registrationId: z.string().min(1, "Registration ID is required"),
	competitionId: z.string().min(1, "Competition ID is required"),
})

/**
 * Remove a registration (soft delete) by an organizer.
 *
 * Sets the registration status to REMOVED and deactivates associated
 * team memberships, heat assignments, and pending invitations.
 * Requires MANAGE_COMPETITIONS permission on the organizing team.
 */
export const removeRegistrationFn = createServerFn({ method: "POST" })
	.inputValidator((data: unknown) => removeRegistrationInputSchema.parse(data))
	.handler(async ({ data: input }) => {
		const session = await getSessionFromCookie()
		if (!session?.userId) throw new Error("Unauthorized")

		const db = getDb()

		updateRequestContext({ userId: session.userId })
		addRequestContextAttribute("competitionId", input.competitionId)
		addRequestContextAttribute("registrationId", input.registrationId)

		// 1. Get competition to verify ownership and get organizing team
		const competition = await db.query.competitionsTable.findFirst({
			where: eq(competitionsTable.id, input.competitionId),
			columns: { id: true, organizingTeamId: true },
		})

		if (!competition) throw new Error("Competition not found")

		// 2. Require organizer permission (site admins bypass)
		if (session.user?.role !== ROLES_ENUM.ADMIN) {
			const team = session.teams?.find(
				(t) => t.id === competition.organizingTeamId,
			)
			if (!team?.permissions.includes(TEAM_PERMISSIONS.MANAGE_COMPETITIONS)) {
				throw new Error("Missing required permission: manage_competitions")
			}
		}

		// 3. Get the registration and verify it belongs to this competition
		const registration = await db.query.competitionRegistrationsTable.findFirst(
			{
				where: and(
					eq(competitionRegistrationsTable.id, input.registrationId),
					eq(competitionRegistrationsTable.eventId, input.competitionId),
				),
			},
		)

		if (!registration) throw new Error("Registration not found")

		if (registration.status === REGISTRATION_STATUS.REMOVED) {
			throw new Error("Registration is already removed")
		}

		logInfo({
			message: "[Registration] Removing registration",
			attributes: {
				registrationId: input.registrationId,
				competitionId: input.competitionId,
				userId: registration.userId,
				athleteTeamId: registration.athleteTeamId ?? "none",
			},
		})

		// 4. Set registration status to REMOVED
		await db
			.update(competitionRegistrationsTable)
			.set({
				status: REGISTRATION_STATUS.REMOVED,
				updatedAt: new Date(),
			})
			.where(eq(competitionRegistrationsTable.id, input.registrationId))

		// 5. Deactivate the captain's team membership in the competition_event team
		await db
			.update(teamMembershipTable)
			.set({ isActive: false })
			.where(eq(teamMembershipTable.id, registration.teamMemberId))

		// 6. For team registrations, deactivate all athlete team memberships and cancel invitations
		if (registration.athleteTeamId) {
			// Deactivate all memberships on the athlete team
			await db
				.update(teamMembershipTable)
				.set({ isActive: false })
				.where(
					and(
						eq(teamMembershipTable.teamId, registration.athleteTeamId),
						eq(teamMembershipTable.isActive, true),
					),
				)

			// Cancel pending invitations for the athlete team
			const { INVITATION_STATUS } = await import("@/db/schema")
			await db
				.update(teamInvitationTable)
				.set({ status: INVITATION_STATUS.CANCELLED })
				.where(
					and(
						eq(teamInvitationTable.teamId, registration.athleteTeamId),
						eq(teamInvitationTable.status, INVITATION_STATUS.PENDING),
					),
				)
		}

		// 7. Delete heat assignments for this registration
		await db
			.delete(competitionHeatAssignmentsTable)
			.where(
				eq(
					competitionHeatAssignmentsTable.registrationId,
					input.registrationId,
				),
			)

		// 8. Delete scores for the registered user(s) in this competition's events
		const { scoresTable, competitionEventsTable } = await import("@/db/schema")

		// Get all competition event IDs
		const competitionEvents = await db
			.select({ id: competitionEventsTable.id })
			.from(competitionEventsTable)
			.where(eq(competitionEventsTable.competitionId, input.competitionId))

		if (competitionEvents.length > 0) {
			const eventIds = competitionEvents.map((e) => e.id)

			// Collect all user IDs to clean up scores for
			const userIds = [registration.userId]

			// For team registrations, also get teammate user IDs
			if (registration.athleteTeamId) {
				const teammates = await db
					.select({ userId: teamMembershipTable.userId })
					.from(teamMembershipTable)
					.where(eq(teamMembershipTable.teamId, registration.athleteTeamId))

				for (const tm of teammates) {
					if (tm.userId && !userIds.includes(tm.userId)) {
						userIds.push(tm.userId)
					}
				}
			}

			// Delete scores for these users in this competition's events
			for (const eventId of eventIds) {
				for (const userId of userIds) {
					await db
						.delete(scoresTable)
						.where(
							and(
								eq(scoresTable.competitionEventId, eventId),
								eq(scoresTable.userId, userId),
							),
						)
				}
			}
		}

		logInfo({
			message: "[Registration] Registration removed successfully",
			attributes: {
				registrationId: input.registrationId,
				competitionId: input.competitionId,
				userId: registration.userId,
			},
		})

		return { success: true }
	})

/**
 * Team Management Route
 * Displays team roster for team competitions and allows management of affiliates.
 * Shows confirmed members, pending invitations, affiliate info, and waiver signing.
 *
 * Port from apps/wodsmith/src/app/(compete)/compete/(public)/[slug]/teams/[registrationId]/page.tsx
 */

import {
	createFileRoute,
	notFound,
	redirect,
	useNavigate,
} from "@tanstack/react-router"
import { eq } from "drizzle-orm"
import {
	CheckCircle,
	ChevronDown,
	Clock,
	Copy,
	Crown,
	Mail,
	Users,
} from "lucide-react"
import { useEffect, useState } from "react"
import { toast } from "sonner"
import { z } from "zod"
import { RegistrationAnswersForm } from "@/components/registration/registration-answers-form"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
	Card,
	CardContent,
	CardDescription,
	CardHeader,
	CardTitle,
} from "@/components/ui/card"
import type { Waiver, WaiverSignature } from "@/db/schemas/waivers"
import {
	getRegistrationDetailsFn,
	getTeamRosterFn,
	type RegistrationDetails,
	type TeamRosterResult,
} from "@/server-fns/registration-fns"
import { getUserCompetitionRegistrationsFn } from "@/server-fns/competition-detail-fns"
import {
	getCompetitionQuestionsFn,
	getRegistrationAnswersFn,
	type RegistrationQuestion,
} from "@/server-fns/registration-questions-fns"
import {
	getCompetitionWaiversFn,
	getWaiverSignaturesForUserFn,
} from "@/server-fns/waiver-fns"
import { AffiliateEditor } from "./-components/affiliate-editor"
import { RegistrationDetailsCard } from "./-components/registration-details"
import { WaiverSection } from "./-components/waiver-section"
import { WelcomeModal } from "./-components/welcome-modal"

// Search params schema
const searchSchema = z.object({
	welcome: z.boolean().optional(),
})

// Types
type RegistrationMetadata = {
	affiliateName?: string // Legacy: captain's affiliate
	affiliates?: Record<string, string> // New: per-user affiliates
}

type PendingTeammate = {
	email: string
	firstName?: string | null
	lastName?: string | null
	affiliateName?: string | null
}

interface UserRegistrationEntry {
	id: string
	divisionId: string | null
	teamName: string | null
	divisionLabel: string | null
}

interface LoaderData {
	registration: TeamRosterResult["registration"]
	registrationDetails: RegistrationDetails | null
	members: TeamRosterResult["members"]
	pending: TeamRosterResult["pending"]
	isTeamRegistration: boolean
	competition: {
		id: string
		name: string
		slug: string
		registrationClosesAt: string | null
	} | null
	division: {
		id: string
		label: string
	} | null
	isTeamMember: boolean
	isRegisteredUser: boolean
	canEditOwnAffiliate: boolean
	currentUserId: string
	memberAffiliates: Record<string, string>
	currentUserAffiliate: string | null
	pendingTeammates: PendingTeammate[]
	waivers: Waiver[]
	waiverSignatures: WaiverSignature[]
	registrationQuestions: RegistrationQuestion[]
	registrationAnswers: Array<{
		id: string
		questionId: string
		registrationId: string
		userId: string
		answer: string
	}>
	allUserRegistrations: UserRegistrationEntry[]
}

export const Route = createFileRoute("/compete/$slug/teams/$registrationId/")({
	component: TeamManagementPage,
	validateSearch: (search) => searchSchema.parse(search),
	loader: async ({ params, context }): Promise<LoaderData> => {
		const { slug, registrationId } = params
		const session = context.session

		// Require authentication
		if (!session) {
			throw redirect({
				to: "/sign-in",
				search: { redirect: `/compete/${slug}/teams/${registrationId}` },
			})
		}

		// Get team roster and registration details first
		const [roster, registrationDetails] = await Promise.all([
			getTeamRosterFn({ data: { registrationId } }),
			getRegistrationDetailsFn({ data: { registrationId } }),
		])

		if (!roster) {
			throw notFound()
		}

		const { registration, members, pending, isTeamRegistration } = roster

		// Check if user is authorized to view this registration
		const isTeamMember = members.some((m) => m.user?.id === session.userId)
		const isRegisteredUser = registration.userId === session.userId

		// If user is not authorized, show 404 (don't reveal that the resource exists)
		if (!isTeamMember && !isRegisteredUser) {
			throw notFound()
		}

		// Now fetch questions, answers, and full competition data if we have a competition
		let registrationQuestions: RegistrationQuestion[] = []
		let registrationAnswers: Array<{
			id: string
			questionId: string
			registrationId: string
			userId: string
			answer: string
		}> = []
		let fullCompetition: { registrationClosesAt: string | null } | null = null

		if (registration.competition?.id) {
			const [questionsResult, answersResult, competitionData] =
				await Promise.all([
					getCompetitionQuestionsFn({
						data: { competitionId: registration.competition.id },
					}).catch(() => ({ questions: [] })),
					getRegistrationAnswersFn({
						data: { registrationId, userId: session.userId },
					}).catch(() => ({ answers: [] })),
					// Fetch full competition data for registrationClosesAt
					(async () => {
						const { getDb } = await import("@/db")
						const { competitionsTable } = await import(
							"@/db/schemas/competitions"
						)
						const db = getDb()
						const compId = registration.competition?.id
						if (!compId) return null
						const comp = await db.query.competitionsTable.findFirst({
							where: eq(competitionsTable.id, compId),
							columns: { registrationClosesAt: true },
						})
						return comp
					})().catch(() => null),
				])

			registrationQuestions = questionsResult.questions
			registrationAnswers = answersResult.answers
			fullCompetition = competitionData || null
		}

		// Parse affiliates from registration metadata
		let memberAffiliates: Record<string, string> = {}
		let currentUserAffiliate: string | null = null

		if (registration.metadata) {
			try {
				const metadata = JSON.parse(
					registration.metadata,
				) as RegistrationMetadata
				// Support new format (affiliates map) and legacy format (affiliateName)
				if (metadata.affiliates) {
					memberAffiliates = metadata.affiliates
				}
				// Legacy: captain's affiliate stored as affiliateName
				if (metadata.affiliateName && registration.captainUserId) {
					memberAffiliates[registration.captainUserId] = metadata.affiliateName
				}
				currentUserAffiliate = memberAffiliates[session.userId] || null
			} catch {
				// Invalid JSON, ignore
			}
		}

		// Parse pending teammates for their affiliate info
		let pendingTeammates: PendingTeammate[] = []
		if (registration.pendingTeammates) {
			try {
				pendingTeammates = JSON.parse(
					registration.pendingTeammates,
				) as PendingTeammate[]
			} catch {
				// Invalid JSON, ignore
			}
		}

		// Fetch waivers and signatures for the competition
		let waivers: Waiver[] = []
		let waiverSignatures: WaiverSignature[] = []

		if (registration.competition?.id) {
			const [waiversResult, signaturesResult] = await Promise.all([
				getCompetitionWaiversFn({
					data: { competitionId: registration.competition.id },
				}),
				getWaiverSignaturesForUserFn({
					data: {
						userId: session.userId,
						competitionId: registration.competition.id,
					},
				}),
			])

			waivers = waiversResult.waivers
			waiverSignatures = signaturesResult.signatures
		}

		const canEditOwnAffiliate = isTeamMember || isRegisteredUser

		// Fetch all user registrations for this competition (for division switcher)
		let allUserRegistrations: UserRegistrationEntry[] = []
		if (registration.competition?.id) {
			try {
				const { registrations: allRegs } =
					await getUserCompetitionRegistrationsFn({
						data: {
							competitionId: registration.competition.id,
							userId: session.userId,
						},
					})

				// Look up division labels for each registration
				if (allRegs.length > 1) {
					const { getDb } = await import("@/db")
					const { scalingLevelsTable } = await import("@/db/schemas/scaling")
					const db = getDb()

					allUserRegistrations = await Promise.all(
						allRegs.map(async (reg) => {
							let divisionLabel: string | null = null
							if (reg.divisionId) {
								const div = await db.query.scalingLevelsTable.findFirst({
									where: eq(scalingLevelsTable.id, reg.divisionId),
									columns: { label: true },
								})
								divisionLabel = div?.label ?? null
							}
							return {
								id: reg.id,
								divisionId: reg.divisionId,
								teamName: reg.teamName,
								divisionLabel,
							}
						}),
					)
				}
			} catch {
				// Non-critical - just won't show division switcher
			}
		}

		return {
			registration,
			registrationDetails,
			members,
			pending,
			isTeamRegistration,
			competition: registration.competition
				? {
						id: registration.competition.id,
						name: registration.competition.name,
						slug: registration.competition.slug,
						registrationClosesAt: fullCompetition?.registrationClosesAt || null,
					}
				: null,
			division: registration.division,
			isTeamMember,
			isRegisteredUser,
			canEditOwnAffiliate,
			currentUserId: session.userId,
			memberAffiliates,
			currentUserAffiliate,
			pendingTeammates,
			waivers,
			waiverSignatures,
			registrationQuestions,
			registrationAnswers,
			allUserRegistrations,
		}
	},
})

function DivisionSwitcher({
	registrations,
	currentRegistrationId,
	competitionSlug,
}: {
	registrations: UserRegistrationEntry[]
	currentRegistrationId: string
	competitionSlug: string
}) {
	const navigate = useNavigate()
	const [open, setOpen] = useState(false)
	const current = registrations.find((r) => r.id === currentRegistrationId)

	return (
		<div className="relative shrink-0">
			<Button
				variant="outline"
				size="sm"
				onClick={() => setOpen(!open)}
				className="justify-between gap-2"
			>
				<span className="truncate max-w-[200px]">
					{current?.divisionLabel ?? "Division"}
					{current?.teamName ? ` - ${current.teamName}` : ""}
				</span>
				<ChevronDown className="h-4 w-4 shrink-0 opacity-50" />
			</Button>
			{open && (
				<div className="absolute right-0 z-10 mt-1 min-w-[200px] rounded-md border bg-popover shadow-md">
					{registrations.map((reg) => (
						<button
							key={reg.id}
							type="button"
							onClick={() => {
								setOpen(false)
								if (reg.id !== currentRegistrationId) {
									navigate({
										to: "/compete/$slug/teams/$registrationId",
										params: {
											slug: competitionSlug,
											registrationId: reg.id,
										},
									})
								}
							}}
							className={`w-full text-left px-3 py-2 text-sm hover:bg-accent ${
								reg.id === currentRegistrationId ? "bg-accent font-medium" : ""
							}`}
						>
							{reg.divisionLabel ?? "Division"}
							{reg.teamName ? ` - ${reg.teamName}` : ""}
						</button>
					))}
				</div>
			)}
		</div>
	)
}

function TeamManagementPage() {
	const {
		registration,
		registrationDetails,
		members,
		pending,
		isTeamRegistration,
		competition,
		division,
		isTeamMember,
		isRegisteredUser,
		canEditOwnAffiliate,
		currentUserId,
		memberAffiliates,
		currentUserAffiliate,
		pendingTeammates,
		waivers,
		waiverSignatures,
		registrationQuestions,
		registrationAnswers,
		allUserRegistrations,
	} = Route.useLoaderData()

	const hasMultipleRegistrations = allUserRegistrations.length > 1

	const { welcome } = Route.useSearch()
	const navigate = useNavigate()
	const [showWelcomeModal, setShowWelcomeModal] = useState(false)

	// Show welcome modal when ?welcome=true is in URL
	useEffect(() => {
		if (welcome) {
			setShowWelcomeModal(true)
			// Clear the welcome param from URL without navigation
			navigate({
				to: ".",
				search: {},
				replace: true,
			})
		}
	}, [welcome, navigate])

	// Calculate if there are unsigned required waivers
	const signedWaiverIds = new Set(waiverSignatures.map((s) => s.waiverId))
	const hasUnsignedWaivers = waivers
		.filter((w) => w.required)
		.some((w) => !signedWaiverIds.has(w.id))

	// Helper to get affiliate for a pending invite by email
	const getPendingAffiliate = (email: string): string | null => {
		const teammate = pendingTeammates.find(
			(t) => t.email.toLowerCase() === email.toLowerCase(),
		)
		return teammate?.affiliateName || null
	}

	const copyInviteLink = async (token: string) => {
		const link = `${window.location.origin}/compete/invite/${token}`
		try {
			await navigator.clipboard.writeText(link)
			toast.success("Invite link copied to clipboard")
		} catch {
			toast.error("Failed to copy invite link")
		}
	}

	// Check if registration is still open for editing
	const isRegistrationOpen =
		!competition?.registrationClosesAt ||
		new Date() < new Date(competition.registrationClosesAt)

	// For individual registrations, show simpler view
	if (!isTeamRegistration) {
		return (
			<div className="container mx-auto max-w-4xl py-8 space-y-6">
				<div className="flex items-start justify-between gap-4">
					<div className="space-y-2">
						<h1 className="text-3xl font-bold">My Registration</h1>
						<p className="text-muted-foreground">
							{competition?.name || "Competition"} –{" "}
							{division?.label || "Division"}
						</p>
					</div>

					{/* Division Switcher - when user has multiple registrations */}
					{hasMultipleRegistrations && competition && (
						<DivisionSwitcher
							registrations={allUserRegistrations}
							currentRegistrationId={registration.id}
							competitionSlug={competition.slug}
						/>
					)}
				</div>

				{/* Registration Details */}
				{registrationDetails && (
					<RegistrationDetailsCard
						details={registrationDetails}
						isTeamRegistration={false}
					/>
				)}

				{/* Registration Questions */}
				{isRegisteredUser && (
					<RegistrationAnswersForm
						registrationId={registration.id}
						questions={registrationQuestions}
						answers={registrationAnswers}
						isEditable={isRegistrationOpen}
						currentUserId={currentUserId}
						isCaptain={true}
					/>
				)}

				{/* Waivers */}
				{isRegisteredUser && waivers.length > 0 && (
					<WaiverSection
						waivers={waivers}
						signatures={waiverSignatures}
						registrationId={registration.id}
						competitionName={competition?.name || "Competition"}
					/>
				)}

				{/* Affiliate */}
				<AffiliateEditor
					registrationId={registration.id}
					userId={currentUserId}
					currentAffiliate={currentUserAffiliate}
					canEdit={canEditOwnAffiliate}
				/>
			</div>
		)
	}

	return (
		<>
			{/* Welcome Modal - shown after accepting invite */}
			<WelcomeModal
				isOpen={showWelcomeModal}
				onClose={() => setShowWelcomeModal(false)}
				teamName={registration.teamName || "Team"}
				competitionName={competition?.name || "Competition"}
				competitionSlug={competition?.slug || ""}
				divisionName={division?.label}
				hasUnsignedWaivers={hasUnsignedWaivers}
			/>

			<div className="container mx-auto max-w-4xl py-8 space-y-6">
				{/* Header */}
				<div className="flex items-start justify-between gap-4">
					<div className="space-y-2">
						<h1 className="text-3xl font-bold">
							{registration.teamName || "Team"}
						</h1>
						<p className="text-muted-foreground">
							{competition?.name || "Competition"} –{" "}
							{division?.label || "Division"}
						</p>
					</div>

					{/* Division Switcher - when user has multiple registrations */}
					{hasMultipleRegistrations && competition && (
						<DivisionSwitcher
							registrations={allUserRegistrations}
							currentRegistrationId={registration.id}
							competitionSlug={competition.slug}
						/>
					)}
				</div>

				{/* Registration Details */}
				{registrationDetails && (
					<RegistrationDetailsCard
						details={registrationDetails}
						isTeamRegistration={true}
					/>
				)}

				{/* Registration Questions */}
				{(isTeamMember || isRegisteredUser) && (
					<RegistrationAnswersForm
						registrationId={registration.id}
						questions={registrationQuestions}
						answers={registrationAnswers}
						isEditable={isRegistrationOpen}
						currentUserId={currentUserId}
						isCaptain={isRegisteredUser}
					/>
				)}

				{/* Team Status Card */}
				<Card>
					<CardHeader>
						<CardTitle className="flex items-center gap-2">
							<Users className="w-5 h-5" />
							Team Roster
						</CardTitle>
						<CardDescription>
							{members.length} confirmed, {pending.length} pending invitation
							{pending.length !== 1 ? "s" : ""}
						</CardDescription>
					</CardHeader>
					<CardContent className="space-y-6">
						{/* Confirmed Members */}
						<div className="space-y-3">
							<h4 className="text-sm font-medium flex items-center gap-2">
								<CheckCircle className="w-4 h-4 text-green-500" />
