														<AvatarFallback>
															<Mail className="w-4 h-4" />
														</AvatarFallback>
													</Avatar>
													<div>
														<p className="font-medium">{invite.email}</p>
														<p className="text-sm text-muted-foreground">
															Invited{" "}
